<body id="top">
@php
    $phoneHref = preg_replace('/[^0-9+]/', '', $content->phone_number);
    $defaults = \App\Models\HomepageContent::defaults();
    $mergeCards = function (array $cards, array $base): array {
        $out = [];
        $count = max(count($cards), count($base));
        for ($i = 0; $i < $count; $i++) {
            $out[] = array_merge(is_array($base[$i] ?? null) ? $base[$i] : [], is_array($cards[$i] ?? null) ? $cards[$i] : []);
        }
        return $out;
    };
    $tourCards = array_values(array_merge(
        $mergeCards($content->destination_cards ?? [], $defaults['destination_cards'] ?? []),
        $mergeCards($content->safari_cards ?? [], $defaults['safari_cards'] ?? []),
    ));
    $count = count($tourCards);
    $country = collect($tourCards)->pluck('country')->filter()->countBy()->sortDesc()->keys()->first() ?? 'Kenya';
    $avg = round((float) (collect($tourCards)->avg(fn ($card) => (float) data_get($card, 'operator_rating', 4.8)) ?: 4.8), 1);
    $reviews = (int) collect($tourCards)->sum(fn ($card) => (int) data_get($card, 'review_count', 0));
    $starts = collect($tourCards)->pluck('start_location')->filter()->countBy()->sortDesc();
    $comforts = collect($tourCards)->pluck('comfort')->filter()->countBy()->sortDesc();
    $days = collect($tourCards)->pluck('duration_days')->filter(fn ($d) => is_numeric($d))->map(fn ($d) => (int) $d);
    $minDays = $days->min() ?? 5;
    $maxDays = $days->max() ?? 7;
    $dayCounts = collect($tourCards)->countBy(fn ($card) => (int) data_get($card, 'duration_days', 0));
    $maxBar = max((int) $dayCounts->max(), 1);
    $initials = function (?string $name): string {
        $parts = preg_split('/\s+/', trim((string) $name)) ?: [];
        $letters = '';
        foreach ($parts as $part) {
            if ($part === '') {
                continue;
            }
            $letters .= strtoupper(substr($part, 0, 1));
            if (strlen($letters) === 2) {
                break;
            }
        }
        return $letters !== '' ? $letters : 'SA';
    };
    $internationalCards = [
        [
            'title' => 'Seychelles',
            'subtitle' => 'Beach Escape + Island Safari Extension',
            'image_url' => 'https://images.pexels.com/photos/247431/pexels-photo-247431.jpeg?auto=compress&cs=tinysrgb&w=1200',
